            Err(e) => {
                ToolResult {
                    task_id: task_id.to_string(),
                    output: String::new(),
                    tokens_used: 0,
                    status: ToolStatus::Failed(format!("Tool iteration failed: {:?}", e)),
                }
            }
        }
    }
}

